const body = $input.first().json.body || $input.first().json;
const reportId = body.report_id;
return [{ json: { report_id: reportId, approved_by: body.approved_by || 'analyst' } }];

const body = $input.first().json.body || $input.first().json;
return [{ json: {
  engagement_id: body.engagement_id,
  report_type: body.report_type || 'technical'
} }];

const eng = $('Get Engagement').first().json;
const findings = $input.all().map(i => i.json);
const engId = $('Normalize Request').first().json.engagement_id;
const reportType = $('Normalize Request').first().json.report_type;

// Severity counts
const sevCount = { critical:0, high:0, medium:0, low:0, informational:0 };
findings.forEach(f => { sevCount[f.severity] = (sevCount[f.severity]||0)+1; });

// OWASP breakdown
const owaspBreakdown = {};
findings.forEach(f => {
  if (f.owasp_category) owaspBreakdown[f.owasp_category] = (owaspBreakdown[f.owasp_category]||0)+1;
});

// Build finding sections
const sections = findings.map((f, idx) => ({
  sort_order: idx,
  section_type: 'finding',
  content: {
    id: f.id,
    title: f.title,
    severity: f.severity,
    recon_score: f.recon_score,
    priority_bucket: f.priority_bucket,
    affected_asset: f.asset_value,
    asset_type: f.asset_type,
    environment: f.environment,
    category: f.category,
    cwe_id: f.cwe_id,
    owasp_category: f.owasp_category,
    validation_status: f.validation_status,
    summary: f.evidence_summary || 'See evidence reference.',
    business_impact: f.business_impact || 'Business impact assessment required.',
    remediation: f.remediation_guidance || 'Remediation guidance required.',
    score_rationale: f.score_explanation,
    analyst_notes: f.analyst_notes,
    is_recurring: f.is_recurring,
    references: f.references || [],
    first_seen: f.first_seen,
    retest_required: f.severity !== 'informational'
  }
}));

// Summary section
const summarySection = {
  sort_order: -1,
  section_type: 'engagement_summary',
  content: {
    client_name: eng.client_name,
    engagement_name: eng.engagement_name,
    engagement_type: eng.type,
    testing_period: `${eng.testing_window_start} - ${eng.testing_window_end}`,
    report_generated_at: new Date().toISOString(),
    report_type: reportType,
    asset_coverage: { total: eng.total_assets, tested: eng.assets_tested, coverage_pct: eng.coverage_pct },
    findings_summary: { ...sevCount, total: findings.length },
    owasp_breakdown: owaspBreakdown,
    top_5_findings: findings.slice(0,5).map(f => ({ title: f.title, severity: f.severity, score: f.recon_score, asset: f.asset_value }))
  }
};

return [{ json: {
  engagement_id: engId,
  report_type: reportType,
  sections: [summarySection, ...sections],
  finding_count: findings.length,
  sev_count: sevCount
} }];

